UPDATE pm_save_item /* base.ec.pm :: PmSaveItem :: updateSelective */
save_id = #{saveId}, site_id = #{siteId}, target_type_cd = #{targetTypeCd}, target_id = #{targetId},
WHERE save_item_id = #{saveItemId}
